async (params, browser) => {
  // Open Tinder
  await browser.open('https://tinder.com/app/recs')

  // Wait for cards
  await browser.waitForSelector('[class*="recsCardboard"], main', 15000)

  // Let card render
  await browser.wait(2000)

  // Click pass
  const result = await browser.evaluate(`const nopeBtn = document.querySelector('[aria-label="Nope"], button[class*="recsGamepad__button--nope"], button[class*="nope"], button[class*="Bgi($g-ds-background-nope)"]'); if (nopeBtn) { nopeBtn.click(); return { success: true, action: 'passed' }; } return { success: false, message: 'Nope button not found' };`)

  return result
}
